{{CSS|content=@import url('https://fonts.googleapis.com/css2?family=Rubik:wght@300;500;700&family=Amatic+SC:wght@400;700&display=swap');

:root {
  --tg-dark: 58, 48, 36;
  --tg-tan: 201, 176, 140;
  --tg-light: 232, 214, 182;
  --tg-gold: 184, 134, 11;
  --tg-soft-gold: 210, 170, 90;
  --tg-shadow: 0, 0, 0;

  --body-font: 'Rubik', sans-serif;
  --retro-font: 'Amatic SC', cursive;
  --mono-font: 'Fantasque Sans Mono', monospace;
}

.page-container .page {
  border: 3px solid rgb(var(--tg-gold));
  margin: 12px auto;
  border-radius: 20px;
  box-shadow: 0 0 18px rgba(var(--tg-gold), 0.4), inset 0 0 8px rgba(var(--tg-light), 0.25);
  background: linear-gradient(
    135deg,
    rgb(var(--tg-dark)),
    rgba(var(--tg-tan), 0.25),
    rgba(var(--tg-light), 0.08)
  );
  background-image:
    repeating-linear-gradient(0deg, rgba(var(--tg-light), 0.05) 0px, transparent 2px, transparent 4px);
}

.theme-fandomdesktop-dark {
  --theme-page-background-color: rgb(var(--tg-dark));
  --theme-page-background-color--secondary: rgba(var(--tg-tan), 0.15);
  --theme-link-color: rgb(var(--tg-light));
  --theme-border-color: rgb(var(--tg-gold));
  --theme-community-header-color: rgb(var(--tg-soft-gold));
  --theme-sticky-nav-background-color: rgba(var(--tg-dark), 0.95);
  --theme-sticky-nav-text-color: rgb(var(--tg-tan));
  --theme-sticky-nav-text-color--hover: rgb(var(--tg-gold));
}

.theme-fandomdesktop-light {
  --theme-page-background-color: rgba(var(--tg-light), 0.95);
  --theme-page-background-color--secondary: rgb(var(--tg-dark));
  --theme-link-color: rgb(var(--tg-dark));
  --theme-border-color: rgb(var(--tg-gold));
  --theme-community-header-color: rgb(var(--tg-gold));
  --theme-sticky-nav-background-color: rgba(var(--tg-light), 0.95);
  --theme-sticky-nav-text-color: rgb(var(--tg-dark));
  --theme-sticky-nav-text-color--hover: rgb(var(--tg-soft-gold));
}

a,
a:visited {
  color: inherit !important;
  text-decoration: none;
  transition: color 0.3s ease, text-shadow 0.3s ease;
}
.theme-fandomdesktop-dark a,
.theme-fandomdesktop-dark a:visited {
  color: rgb(var(--tg-light)) !important;
}
.theme-fandomdesktop-light a,
.theme-fandomdesktop-light a:visited {
  color: rgb(var(--tg-dark)) !important;
}
a:hover,
a:focus {
  color: rgb(var(--tg-gold)) !important;
  text-shadow: 0 0 6px rgba(var(--tg-gold), 0.6),
               0 0 10px rgba(var(--tg-soft-gold), 0.4);
}

.page-side-tools .page-side-tool {
  border: 2px solid rgb(var(--tg-gold));
  box-shadow: 0 0 10px rgba(var(--tg-gold), 0.5);
  border-radius: 50%;
  background-color: rgba(var(--tg-dark), 0.9);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.page-side-tool:hover {
  transform: scale(1.1) rotate(2deg);
  box-shadow: 0 0 18px rgba(var(--tg-soft-gold), 0.7);
}

.titleblock, .dark-titleblock {
  background: radial-gradient(circle at top, rgba(var(--tg-tan), 0.25), rgba(var(--tg-dark), 0.95));
  border: 3px solid rgb(var(--tg-gold));
  border-radius: 25px;
  padding: 1rem;
  font-family: var(--retro-font);
  font-weight: 700;
  color: rgb(var(--tg-light));
  text-shadow: 0 0 5px rgba(var(--tg-light), 0.8), 0 0 12px rgba(var(--tg-soft-gold), 0.5);
  font-size: 2.3em;
  letter-spacing: 2px;
  transform: rotate(-1deg);
  animation: gold-flicker 2.5s infinite alternate;
}

.progress {
  background: rgba(var(--tg-dark), 0.95);
  border: 2px solid rgb(var(--tg-gold));
  border-radius: 15px;
  color: rgb(var(--tg-light));
  box-shadow: 0 0 8px rgba(var(--tg-gold), 0.5);
}
.progress .bar {
  background: linear-gradient(to right, rgb(var(--tg-tan)), rgb(var(--tg-gold)));
  border-radius: 12px;
  box-shadow: 0 0 12px rgba(var(--tg-soft-gold), 0.6);
}

h1, h2, h3, h4, h5, h6 {
  font-family: var(--retro-font);
  color: rgb(var(--tg-soft-gold));
  text-transform: uppercase;
  letter-spacing: 4px;
  text-shadow: 0 0 5px rgba(var(--tg-light), 0.6), 0 0 10px rgba(var(--tg-gold), 0.4);
  font-size: calc(1.5rem + 0.6vw);
}
h1 {
  font-size: calc(2rem + 1.2vw);
}

.theme-fandomdesktop-light h1,
.theme-fandomdesktop-light h2,
.theme-fandomdesktop-light h3,
.theme-fandomdesktop-light h4,
.theme-fandomdesktop-light h5,
.theme-fandomdesktop-light h6 {
  color: rgb(var(--tg-gold));
  text-shadow: 0 0 4px rgba(var(--tg-light), 0.5), 0 0 8px rgba(var(--tg-tan), 0.4);
}

@keyframes gold-flicker {
  0%, 18%, 22%, 60%, 65%, 100% {
    opacity: 1;
    text-shadow: 0 0 6px rgba(var(--tg-light), 0.9), 0 0 14px rgba(var(--tg-soft-gold), 0.6);
  }
  20%, 63% {
    opacity: 0.75;
    text-shadow: none;
  }
}
}}

